cd ~/.openclaw/workspace/tools && .venv/bin/python3 -c "
import json, os, httpx

url = os.environ.get('SUPABASE_URL', '') + '/rest/v1/sai_memory'
key = os.environ.get('SUPABASE_ANON_KEY', '')
headers = {
    'apikey': key,
    'Authorization': f'Bearer {key}',
    'Content-Type': 'application/json'
}
params = {'select': 'content', 'category': 'eq.position_mastery', 'limit': '100'}
r = httpx.get(url, headers=headers, params=params)
rows = r.json()
positions = []
for row in rows:
    try:
        data = json.loads(row['content']) if isinstance(row['content'], str) else row['content']
        positions.append(f\"{data.get('cluster_family','?')} > {data.get('cluster_name','?')} > {data.get('position_name','?')}\")
    except:
        pass
print(f'Total positions researched: {len(positions)}')
for p in sorted(positions):
    print(p)
"
